'use client';

import Image from 'next/image';
import Link from 'next/link';
import { Badge } from '@/components/ui/badge';
import type { Anime } from '@/types/anime';

interface AnimeCardProps {
  anime: Anime;
}

export function AnimeCard({ anime }: AnimeCardProps) {
  const languages = anime.available_languages?.split(',') || [];

  return (
    <Link href={`/anime/${anime.slug}`} className="group block">
      <div className="relative aspect-[2/3] rounded-xl overflow-hidden bg-gradient-to-br from-purple-900/20 to-slate-900/20 ring-1 ring-white/10 transition-all duration-300 hover:ring-purple-500/50 hover:shadow-xl hover:shadow-purple-900/20 hover:scale-105">
        {/* Image */}
        {anime.cover_url ? (
          <Image
            src={anime.cover_url}
            alt={anime.title}
            fill
            className="object-cover transition-transform duration-500 group-hover:scale-110"
            sizes="(max-width: 640px) 50vw, (max-width: 1024px) 33vw, 20vw"
          />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center bg-gradient-to-br from-purple-600/30 to-pink-600/30">
            <span className="text-4xl font-bold text-white/50">
              {anime.title.charAt(0)}
            </span>
          </div>
        )}

        {/* Gradient overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/60 to-transparent opacity-60 group-hover:opacity-70 transition-opacity" />

        {/* Classic badge */}
        {anime.is_classic === 1 && (
          <div className="absolute top-2 left-2 z-10">
            <Badge className="bg-amber-500/90 text-amber-950 text-[10px] font-bold px-2 py-0.5">
              Classique
            </Badge>
          </div>
        )}

        {/* Language badges */}
        <div className="absolute top-2 right-2 z-10 flex gap-1">
          {languages.map((lang) => (
            <Badge
              key={lang}
              variant="outline"
              className={`text-[9px] font-bold px-1.5 py-0 border-0 ${
                lang.trim() === 'VF' 
                  ? 'bg-blue-500/80 text-white' 
                  : lang.trim() === 'VOSTFR'
                  ? 'bg-purple-500/80 text-white'
                  : 'bg-white/20 text-white'
              }`}
            >
              {lang.trim()}
            </Badge>
          ))}
        </div>

        {/* Type badge */}
        <div className="absolute bottom-12 left-2 z-10">
          <Badge className="bg-fuchsia-500/20 text-fuchsia-300 border border-fuchsia-500/30 text-[10px]">
            {anime.type || 'Anime'}
          </Badge>
        </div>

        {/* Episode count */}
        <div className="absolute bottom-12 right-2 z-10">
          <Badge className="bg-purple-500/20 text-purple-300 border border-purple-500/30 text-[10px]">
            {anime.episode_count} ép.
          </Badge>
        </div>

        {/* Title at bottom */}
        <div className="absolute bottom-0 left-0 right-0 p-2.5 z-10">
          <h3 className="font-bold text-white text-sm line-clamp-2 group-hover:text-purple-200 transition-colors">
            {anime.title}
          </h3>
          {anime.release_year && (
            <p className="text-xs text-gray-400 mt-0.5">{anime.release_year}</p>
          )}
        </div>

        {/* Hover overlay with play icon */}
        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <div className="w-14 h-14 rounded-full bg-white/20 backdrop-blur-sm flex items-center justify-center ring-2 ring-white/30">
            <svg className="w-6 h-6 text-white ml-1" fill="currentColor" viewBox="0 0 24 24">
              <path d="M8 5v14l11-7z"/>
            </svg>
          </div>
        </div>
      </div>
    </Link>
  );
}

