'use client';

import Image from 'next/image';
import Link from 'next/link';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import type { AnimeDetail, Episode } from '@/types/anime';

interface AnimeDetailProps {
  anime: AnimeDetail;
}

function groupEpisodesBySeason(episodes: Episode[]) {
  const seasons: Record<number, Episode[]> = {};

  episodes.forEach((episode) => {
    const season = episode.season_number || 1;
    if (!seasons[season]) {
      seasons[season] = [];
    }
    seasons[season].push(episode);
  });

  // Sort episodes within each season
  Object.keys(seasons).forEach((season) => {
    seasons[parseInt(season)].sort((a, b) => a.episode_number - b.episode_number);
  });

  return seasons;
}

export function AnimeDetail({ anime }: AnimeDetailProps) {
  const languages = anime.available_languages?.split(',') || [];
  const seasons = groupEpisodesBySeason(anime.episodes || []);
  const seasonNumbers = Object.keys(seasons).map(Number).sort((a, b) => a - b);
  const hasMultipleSeasons = seasonNumbers.length > 1;

  return (
    <div className="min-h-screen">
      {/* Banner */}
      <div className="relative w-full h-[40vh] md:h-[50vh] overflow-hidden">
        {anime.banner_url ? (
          <Image
            src={anime.banner_url}
            alt={anime.title}
            fill
            className="object-cover"
            priority
          />
        ) : anime.cover_url ? (
          <Image
            src={anime.cover_url}
            alt={anime.title}
            fill
            className="object-cover"
            priority
          />
        ) : (
          <div className="absolute inset-0 bg-gradient-to-br from-purple-900 to-slate-900" />
        )}

        {/* Gradient overlays */}
        <div className="absolute inset-0 bg-gradient-to-t from-[#0B0A12] via-[#0B0A12]/80 to-transparent" />
        <div className="absolute inset-0 bg-gradient-to-r from-[#0B0A12] via-[#0B0A12]/60 to-transparent" />
      </div>

      {/* Content */}
      <div className="relative -mt-48 z-10 px-4 md:px-8 lg:px-16">
        <div className="flex flex-col lg:flex-row gap-8">
          {/* Cover */}
          <div className="flex-shrink-0">
            <div className="relative w-48 md:w-64 aspect-[2/3] rounded-xl overflow-hidden shadow-2xl ring-1 ring-white/10">
              {anime.cover_url ? (
                <Image
                  src={anime.cover_url}
                  alt={anime.title}
                  fill
                  className="object-cover"
                />
              ) : (
                <div className="absolute inset-0 bg-gradient-to-br from-purple-600 to-pink-600 flex items-center justify-center">
                  <span className="text-6xl font-bold text-white/50">
                    {anime.title.charAt(0)}
                  </span>
                </div>
              )}

              {/* Language badges on cover */}
              <div className="absolute top-2 right-2 flex gap-1">
                {languages.map((lang) => (
                  <Badge
                    key={lang}
                    className={`text-[9px] font-bold px-1.5 py-0 border-0 ${
                      lang.trim() === 'VF'
                        ? 'bg-blue-500/90 text-white'
                        : lang.trim() === 'VOSTFR'
                        ? 'bg-purple-500/90 text-white'
                        : 'bg-white/20 text-white'
                    }`}
                  >
                    {lang.trim()}
                  </Badge>
                ))}
              </div>
            </div>
          </div>

          {/* Info */}
          <div className="flex-1 pt-4">
            <h1 className="text-3xl md:text-4xl lg:text-5xl font-bold text-white mb-4">
              {anime.title}
            </h1>

            {/* Meta info */}
            <div className="flex flex-wrap gap-3 mb-4">
              {anime.release_year && (
                <Badge className="bg-white/10 text-white border-white/20">
                  {anime.release_year}
                </Badge>
              )}
              <Badge className="bg-fuchsia-500/20 text-fuchsia-300 border border-fuchsia-500/30">
                {anime.type || 'Anime'}
              </Badge>
              {anime.episode_count > 0 && (
                <Badge className="bg-purple-500/20 text-purple-300 border border-purple-500/30">
                  {anime.episode_count} épisodes
                </Badge>
              )}
              {anime.is_classic === 1 && (
                <Badge className="bg-amber-500/20 text-amber-300 border border-amber-500/30">
                  Classique
                </Badge>
              )}
            </div>

            {/* Genres */}
            <div className="flex flex-wrap gap-2 mb-6">
              {anime.genres?.map((genre) => (
                <Link key={genre.id} href={`/?genre=${genre.id}`}>
                  <Badge
                    variant="outline"
                    className="border-purple-500/30 text-purple-300 hover:bg-purple-500/20 cursor-pointer transition-colors"
                  >
                    {genre.name}
                  </Badge>
                </Link>
              ))}
            </div>

            {/* Synopsis */}
            {anime.synopsis && (
              <div className="mb-6 max-w-3xl">
                <h3 className="text-lg font-semibold text-white mb-2">Synopsis</h3>
                <p className="text-gray-300 leading-relaxed whitespace-pre-line">
                  {anime.synopsis}
                </p>
              </div>
            )}

            {/* Action buttons */}
            <div className="flex gap-4">
              <Button className="bg-white text-black hover:bg-gray-200 px-8 py-6 rounded-full font-bold text-sm uppercase tracking-wider">
                <svg className="w-5 h-5 mr-2 fill-current" viewBox="0 0 24 24">
                  <path d="M8 5v14l11-7z"/>
                </svg>
                Regarder
              </Button>
              <Button variant="outline" className="border-white/20 text-white hover:bg-white/10 px-6 py-6 rounded-full">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                Ma Liste
              </Button>
            </div>
          </div>
        </div>

        {/* Episodes section */}
        {anime.episodes && anime.episodes.length > 0 && (
          <div className="mt-12">
            <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-3">
              <div className="w-1 h-8 bg-gradient-to-b from-purple-500 to-pink-500 rounded-full" />
              Épisodes
            </h2>

            {hasMultipleSeasons ? (
              <Tabs defaultValue={seasonNumbers[0]?.toString()} className="w-full">
                <TabsList className="bg-white/5 border border-white/10 mb-6">
                  {seasonNumbers.map((season) => (
                    <TabsTrigger
                      key={season}
                      value={season.toString()}
                      className="data-[state=active]:bg-purple-600 data-[state=active]:text-white text-gray-400"
                    >
                      Saison {season}
                    </TabsTrigger>
                  ))}
                </TabsList>
                {seasonNumbers.map((season) => (
                  <TabsContent key={season} value={season.toString()}>
                    <EpisodeList episodes={seasons[season]} />
                  </TabsContent>
                ))}
              </Tabs>
            ) : (
              <EpisodeList episodes={anime.episodes} />
            )}
          </div>
        )}
      </div>
    </div>
  );
}

function EpisodeList({ episodes }: { episodes: Episode[] }) {
  return (
    <ScrollArea className="h-[400px] pr-4">
      <div className="space-y-2">
        {episodes.map((episode) => (
          <div
            key={episode.id}
            className="flex gap-4 p-3 rounded-lg bg-white/5 hover:bg-white/10 transition-colors cursor-pointer group"
          >
            {/* Thumbnail */}
            <div className="relative w-40 aspect-video rounded-md overflow-hidden flex-shrink-0 bg-slate-800">
              {episode.thumbnail_url ? (
                <Image
                  src={episode.thumbnail_url}
                  alt={`Épisode ${episode.episode_number}`}
                  fill
                  className="object-cover"
                />
              ) : (
                <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-2xl font-bold text-white/30">
                    {episode.episode_number}
                  </span>
                </div>
              )}
              <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/40">
                <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center">
                  <svg className="w-5 h-5 text-white ml-0.5" fill="currentColor" viewBox="0 0 24 24">
                    <path d="M8 5v14l11-7z"/>
                  </svg>
                </div>
              </div>
            </div>

            {/* Info */}
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 mb-1">
                <span className="text-purple-400 font-medium text-sm">
                  Épisode {episode.episode_number}
                </span>
                {episode.duration && (
                  <span className="text-gray-500 text-xs">
                    {Math.floor(episode.duration / 60)} min
                  </span>
                )}
              </div>
              {episode.title && (
                <h4 className="text-white font-medium truncate group-hover:text-purple-200 transition-colors">
                  {episode.title}
                </h4>
              )}
              {episode.synopsis && (
                <p className="text-gray-400 text-sm line-clamp-2 mt-1">
                  {episode.synopsis}
                </p>
              )}
              <div className="flex gap-1 mt-2">
                {episode.languages?.map((lang) => (
                  <Badge
                    key={lang}
                    variant="outline"
                    className="text-[9px] border-white/20 text-gray-400"
                  >
                    {lang}
                  </Badge>
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>
    </ScrollArea>
  );
}

