'use client';

import { useState } from 'react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import type { AnimesFilters, Genre } from '@/types/anime';

interface SearchFiltersProps {
  filters: AnimesFilters;
  onFiltersChange: (filters: AnimesFilters) => void;
  genres: Genre[];
  total: number;
}

const animeTypes = [
  { value: 'all', label: 'Tous les types' },
  { value: 'Anime', label: 'Anime' },
  { value: 'Film', label: 'Film' },
  { value: 'OAV', label: 'OAV' },
  { value: 'Special', label: 'Spécial' },
];

const sortOptions = [
  { value: 'created_at', label: 'Plus récents' },
  { value: 'title', label: 'Titre A-Z' },
  { value: 'release_year', label: 'Année' },
  { value: 'rating', label: 'Note' },
];

const currentYear = new Date().getFullYear();
const years = Array.from({ length: 30 }, (_, i) => currentYear - i);

export function SearchFilters({ filters, onFiltersChange, genres, total }: SearchFiltersProps) {
  const [searchValue, setSearchValue] = useState(filters.search || '');

  const handleSearch = (value: string) => {
    setSearchValue(value);
    // Debounced search would be better, but for simplicity we search on Enter
  };

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onFiltersChange({ ...filters, search: searchValue, page: 1 });
  };

  const handleTypeChange = (value: string) => {
    onFiltersChange({
      ...filters,
      type: value === 'all' ? undefined : value,
      page: 1,
    });
  };

  const handleGenreChange = (value: string) => {
    onFiltersChange({
      ...filters,
      genre: value === 'all' ? undefined : parseInt(value),
      page: 1,
    });
  };

  const handleYearChange = (value: string) => {
    onFiltersChange({
      ...filters,
      year: value === 'all' ? undefined : parseInt(value),
      page: 1,
    });
  };

  const handleSortChange = (value: string) => {
    onFiltersChange({
      ...filters,
      sort_by: value as AnimesFilters['sort_by'],
      page: 1,
    });
  };

  const clearFilters = () => {
    setSearchValue('');
    onFiltersChange({ limit: 20, page: 1 });
  };

  const hasActiveFilters = filters.search || filters.type || filters.genre || filters.year;

  return (
    <div className="space-y-4">
      {/* Search bar */}
      <form onSubmit={handleSearchSubmit} className="flex gap-2">
        <div className="relative flex-1">
          <svg
            className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
            />
          </svg>
          <Input
            type="text"
            placeholder="Rechercher un anime..."
            value={searchValue}
            onChange={(e) => handleSearch(e.target.value)}
            className="pl-10 bg-white/5 border-white/10 text-white placeholder:text-gray-500 focus:border-purple-500 focus:ring-purple-500/20"
          />
        </div>
        <Button type="submit" className="bg-purple-600 hover:bg-purple-700 text-white">
          Rechercher
        </Button>
      </form>

      {/* Filters row */}
      <div className="flex flex-wrap gap-3 items-center">
        {/* Type filter */}
        <Select value={filters.type || 'all'} onValueChange={handleTypeChange}>
          <SelectTrigger className="w-[140px] bg-white/5 border-white/10 text-white">
            <SelectValue placeholder="Type" />
          </SelectTrigger>
          <SelectContent className="bg-slate-900 border-white/10">
            {animeTypes.map((type) => (
              <SelectItem key={type.value} value={type.value} className="text-white hover:bg-white/10">
                {type.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {/* Genre filter */}
        <Select 
          value={filters.genre?.toString() || 'all'} 
          onValueChange={handleGenreChange}
        >
          <SelectTrigger className="w-[160px] bg-white/5 border-white/10 text-white">
            <SelectValue placeholder="Genre" />
          </SelectTrigger>
          <SelectContent className="bg-slate-900 border-white/10 max-h-[300px]">
            <SelectItem value="all" className="text-white hover:bg-white/10">
              Tous les genres
            </SelectItem>
            {genres.map((genre) => (
              <SelectItem key={genre.id} value={genre.id.toString()} className="text-white hover:bg-white/10">
                {genre.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {/* Year filter */}
        <Select 
          value={filters.year?.toString() || 'all'} 
          onValueChange={handleYearChange}
        >
          <SelectTrigger className="w-[120px] bg-white/5 border-white/10 text-white">
            <SelectValue placeholder="Année" />
          </SelectTrigger>
          <SelectContent className="bg-slate-900 border-white/10 max-h-[300px]">
            <SelectItem value="all" className="text-white hover:bg-white/10">
              Toutes
            </SelectItem>
            {years.map((year) => (
              <SelectItem key={year} value={year.toString()} className="text-white hover:bg-white/10">
                {year}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {/* Sort */}
        <Select 
          value={filters.sort_by || 'created_at'} 
          onValueChange={handleSortChange}
        >
          <SelectTrigger className="w-[140px] bg-white/5 border-white/10 text-white">
            <SelectValue placeholder="Trier par" />
          </SelectTrigger>
          <SelectContent className="bg-slate-900 border-white/10">
            {sortOptions.map((option) => (
              <SelectItem key={option.value} value={option.value} className="text-white hover:bg-white/10">
                {option.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {/* Clear filters */}
        {hasActiveFilters && (
          <Button
            variant="ghost"
            onClick={clearFilters}
            className="text-gray-400 hover:text-white hover:bg-white/10"
          >
            Effacer les filtres
          </Button>
        )}
      </div>

      {/* Results count */}
      <div className="flex items-center gap-2">
        <Badge variant="outline" className="border-purple-500/30 text-purple-300">
          {total.toLocaleString()} animes
        </Badge>
        {filters.search && (
          <Badge className="bg-purple-500/20 text-purple-300 border border-purple-500/30">
            &quot;{filters.search}&quot;
          </Badge>
        )}
      </div>
    </div>
  );
}

